\begin{aligned}
U_{j}^{n+1}=U_{j}^{n}-\frac{1}{2} \frac{\Delta t}{\Delta x}\{ & {\left[1-A_{j+1 / 2}^{n} \frac{\Delta t}{\Delta x}\right] \Delta_{+x} F_{j}^{n} } \\
